import './TableCell.scss';

import { Icon } from ':components/Icon';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React from 'react';

import type { TableCellProps } from './TableCell.types';

/**
 * @name TableCell
 * @prop {ReactEventHandler} onClick нажаие по кнопке
 * @prop {isExpanded} isExpanded состояния открыта/закрыта
 */
export const TableCell: FC<TableCellProps> = ({ onClick, isExpanded }: TableCellProps) => (
	<div className="dsb_table-cell__icon" data-testid="TableCell">
		<Icon size="small" onClick={onClick} iconName={isExpanded ? Icons.NavArrowUp : Icons.NavArrowDown} />
	</div>
);
